import{c as o,Q as t,j as r,m as a}from"./chunks/framework.CLEOx5cX.js";const u=JSON.parse('{"title":"Open Source and Protected Core","description":"","frontmatter":{},"headers":[],"relativePath":"protected-core.md","filePath":"protected-core.md","lastUpdated":1780286224000}'),i={name:"protected-core.md"};function n(l,e,c,s,d,p){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="open-source-and-protected-core" tabindex="-1">Open Source and Protected Core <a class="header-anchor" href="#open-source-and-protected-core" aria-label="Permalink to &quot;Open Source and Protected Core&quot;">​</a></h1><p>Oskar scripts are structured to keep adaptation work simple while protecting the files that should not be touched by most server owners.</p><h2 id="open-files" tabindex="-1">Open Files <a class="header-anchor" href="#open-files" aria-label="Permalink to &quot;Open Files&quot;">​</a></h2><p>Open files are intended for configuration and framework adaptation.</p><p>Common examples:</p><ul><li><code>config/</code></li><li><code>functions/</code></li><li><code>frameworks/</code></li><li>Public integration helpers.</li><li>Documentation.</li></ul><p>These files are where server owners should adapt inventory, money, permissions, framework methods, profile image lookups, rewards, and public events.</p><h2 id="protected-core" tabindex="-1">Protected Core <a class="header-anchor" href="#protected-core" aria-label="Permalink to &quot;Protected Core&quot;">​</a></h2><p>Protected core files contain the logic that should stay stable across servers.</p><p>Common examples:</p><ul><li>Main client logic.</li><li>Main server logic.</li><li>Authentication or license checks.</li><li>Sensitive flow control.</li></ul><p>The goal is to avoid editing this layer directly. If something needs to be adapted, it should be exposed through an open function, adapter, config value, export, or event.</p><h2 id="recommended-workflow" tabindex="-1">Recommended Workflow <a class="header-anchor" href="#recommended-workflow" aria-label="Permalink to &quot;Recommended Workflow&quot;">​</a></h2><ol><li>Choose the active framework in the config.</li><li>Edit the framework adapter if your base needs custom behavior.</li><li>Use open function files for server-specific logic.</li><li>Keep protected core files untouched.</li><li>Document any local changes in the script page.</li></ol>',14)])])}const f=o(i,[["render",n]]);export{u as __pageData,f as default};
